import { Box, Flex, VStack } from '@chakra-ui/layout';
import { titleOptions } from '@constants';
import { ICommitmentShow, IDonorDetails, IUpdateCommitment, RepeatEnum } from '@domain/commitment';
import { CommitmentSchedule } from '@domain/commitments/commitmentSchedule';
import { IErrorResponse } from '@domain/error';
import { serializeDate } from '@ui/components/filters/serde';
import {
  addressControlFormSchema,
  FormAddressControl,
} from '@ui/components/formControls/compositions/AddressControl';
import { Form } from '@ui/components/formControls/Form';
import { FormGroup } from '@ui/components/formControls/FormGroup';
import { FormSection } from '@ui/components/formControls/FormSection';
import { FormInputControl } from '@ui/components/formControls/InputControl';
import { FormMaskedInputControl } from '@ui/components/formControls/MaskedInputControl';
import { FormSelectControl } from '@ui/components/formControls/SelectControl';
import { parseDate } from '@ui/utils/parseDate';
import { isFirstAndFifteenth } from '@utils/isFirstAndFifteenth';
import * as yup from 'yup';
import { FormSchedule } from './components/FormSchedule';
import { UpcomingSchedulePreview } from './components/UpcomingSchedulePreview';
import { ICommitmentForm } from './constants';

const schema: yup.Schema<ICommitmentForm> = yup
  .object()
  .shape({
    daysOfMonth: yup.array(),
    daysOfWeek: yup.array(),
    email: yup.string().email('Enter a valid email'),
    endDate: yup.date().nullable().typeError('Enter a valid end date'),
    every: yup.string().when('repeat', {
      is: (repeat: string) => repeat === RepeatEnum.Weekly || repeat === RepeatEnum.Monthly,
      then: () => yup.string().required('Enter an Every'),
    }),
    firstName: yup.string().required('Enter a First Name'),
    lastName: yup.string().required('Enter a Last Name'),
    middleName: yup.string(),
    occurrences: yup.string(),
    phone: yup.string(),
    repeat: yup.mixed<RepeatEnum>().oneOf(Object.values(RepeatEnum), 'Select a Repetition'),
    suffix: yup.string(),
    title: yup.string(),
    totalAmount: yup
      .string()
      .required('Enter an Amount')
      .test('amount', 'Amount must be greater than $1.00', (value) =>
        value ? parseInt(value, 10) * 100 >= 100 : false
      ),
  })
  .concat(addressControlFormSchema);

interface IProps {
  error: IErrorResponse | null;
  existingCommitment?: ICommitmentShow;
  id: string;
  onSubmit: (data: DeepPartial<IUpdateCommitment>) => void;
}

export const CommitmentForm = ({ error, existingCommitment, id, onSubmit }: IProps) => {
  const amountAllocation =
    (existingCommitment?.amountAllocationsAttributes || []).length > 0
      ? existingCommitment?.amountAllocationsAttributes[0]
      : null;

  const handleSubmit = (values: ICommitmentForm) => {
    const donorDetailsAttributes: IDonorDetails = {
      email: values.email ?? '',
      employerName: values.employerName ?? '',
      firstName: values.firstName,
      id: existingCommitment?.donorDetailsAttributes?.id ?? '',
      lastName: values.lastName,
      middleName: values.middleName,
      occupation: values.occupation ?? '',
      phone: values.phone,
      suffix: values.suffix,
      title: values.title,
    };

    const scheduleAttributes: Partial<CommitmentSchedule> = {
      daysOfMonth: (values.daysOfMonth ?? []).map((day) => parseInt(day, 10)),
      daysOfWeek: values.daysOfWeek ?? [],
      every: values.repeat!,
      interval: values.every ? parseInt(values.every, 10) : null,
      total: values.occurrences ? parseInt(values.occurrences, 10) : null,
      until: values.endDate ? serializeDate(values.endDate) : null,
    };

    if (scheduleAttributes.every === RepeatEnum.FirstAndFifteenth) {
      scheduleAttributes.daysOfMonth = [1, 15];
      scheduleAttributes.every = RepeatEnum.Monthly;
    }

    onSubmit({
      addressAttributes: {
        city: values.city ?? '',
        country: values.country ?? '',
        id: existingCommitment?.addressAttributes?.id ?? '',
        line1: values.line1 ?? '',
        line2: values.line2 ?? '',
        postalCode: values.postalCode ?? '',
        region: values.region ?? '',
      },
      amountAllocationsAttributes: [
        {
          amount: Math.round(parseFloat(values.totalAmount) * 100),
          id: amountAllocation?.id,
        },
      ],
      donorDetailsAttributes,
      scheduleAttributes,
    });
  };

  return (
    <Form
      enableReinitialize
      id={id}
      initialValues={
        {
          city: existingCommitment?.addressAttributes?.city || '',
          country: existingCommitment?.addressAttributes?.country || '',
          daysOfMonth: existingCommitment?.scheduleAttributes?.daysOfMonth.map((x) => `${x}`) ?? [],
          daysOfWeek: existingCommitment?.scheduleAttributes?.daysOfWeek ?? [],
          email: existingCommitment?.donorDetailsAttributes?.email || '',
          employerName: existingCommitment?.donorDetailsAttributes?.employerName || '',
          endDate: existingCommitment?.scheduleAttributes?.until
            ? parseDate(existingCommitment?.scheduleAttributes?.until.split('T')[0])
            : null,
          every: existingCommitment?.scheduleAttributes?.interval ?? '1',
          firstName: existingCommitment?.donorDetailsAttributes?.firstName || '',
          lastName: existingCommitment?.donorDetailsAttributes?.lastName || '',
          line1: existingCommitment?.addressAttributes?.line1 || '',
          line2: existingCommitment?.addressAttributes?.line2 || '',
          middleName: existingCommitment?.donorDetailsAttributes?.middleName || '',
          occupation: existingCommitment?.donorDetailsAttributes?.occupation || '',
          occurrences: existingCommitment?.scheduleAttributes?.total || '',
          phone: existingCommitment?.donorDetailsAttributes?.phone || '',
          postalCode: existingCommitment?.addressAttributes?.postalCode || '',
          region: existingCommitment?.addressAttributes?.region || '',
          repeat: isFirstAndFifteenth(
            existingCommitment?.scheduleAttributes?.daysOfMonth,
            existingCommitment?.scheduleAttributes?.every
          )
            ? RepeatEnum.FirstAndFifteenth
            : existingCommitment?.scheduleAttributes?.every || '',
          suffix: existingCommitment?.donorDetailsAttributes?.suffix || '',
          title: existingCommitment?.donorDetailsAttributes?.title ?? '',
          totalAmount: amountAllocation ? amountAllocation.amount / 100 : '',
        } as ICommitmentForm
      }
      onSubmit={handleSubmit}
      schema={schema}
      serverError={error}
    >
      {({ watch }) => {
        const totalAmount = watch('totalAmount');
        const repeat = watch('repeat');
        const occurrences = watch('occurrences');
        const endDate = watch('endDate');
        const every = watch('every');
        const daysOfWeek = watch('daysOfWeek');
        const daysOfMonth = watch('daysOfMonth');
        return (
          <VStack alignItems="stretch" spacing={8}>
            <FormSection title="Contact Information">
              <FormGroup title="Name">
                <Flex gap={2}>
                  <FormInputControl label="First Name" name="firstName" placeholder="First name" />
                  <FormInputControl label="Last Name" name="lastName" placeholder="Last name" />
                </Flex>
                <Flex gap={2}>
                  <Box minW="200px">
                    <FormInputControl
                      label="Middle Name"
                      name="middleName"
                      placeholder="Middle name"
                    />
                  </Box>
                  <Flex gap={2}>
                    <FormSelectControl
                      label="Title"
                      name="title"
                      options={titleOptions}
                      placeholder="-"
                    />
                    <FormInputControl label="Suffix" name="suffix" placeholder="-" />
                  </Flex>
                </Flex>
              </FormGroup>

              <FormGroup title="Contact">
                <Flex gap={2}>
                  <FormInputControl label="Email" name="email" placeholder="annie@example.com" />
                  <FormMaskedInputControl label="Phone" name="phone" type="phone" />
                </Flex>
              </FormGroup>

              <FormGroup title="Address">
                <FormAddressControl />
              </FormGroup>
            </FormSection>

            <FormSection title="Employment">
              <FormGroup>
                <Flex gap={2}>
                  <FormInputControl label="Occupation" name="occupation" placeholder="Occupation" />
                  <FormInputControl label="Employer" name="employerName" placeholder="Employer" />
                </Flex>
              </FormGroup>
            </FormSection>

            <FormSection title="Commitment">
              <FormGroup>
                <FormSchedule />
                <UpcomingSchedulePreview
                  amount={totalAmount ? `${parseFloat(totalAmount) * 100}` : ''}
                  daysOfMonth={daysOfMonth}
                  daysOfWeek={daysOfWeek}
                  endDate={endDate}
                  every={every}
                  occurrences={occurrences}
                  repeat={repeat}
                />
              </FormGroup>
            </FormSection>
          </VStack>
        );
      }}
    </Form>
  );
};

