import { Box } from '@chakra-ui/react';
import { RepeatEnum } from '@domain/commitment';
import { DaysOfWeek } from '@domain/common';
import { useGetCommitmentPaymentSchedulePreview } from '@state/commitments';
import { serializeDate } from '@ui/components/filters/serde';
import { Heading } from '@ui/components/typography';
import { UpcomingSchedule, UpcomingScheduleSkeleton } from '@ui/components/UpcomingSchedule';

interface IProps {
  amount: string;
  daysOfMonth: string[] | undefined;
  daysOfWeek: DaysOfWeek[] | undefined;
  endDate: Date | null | undefined;
  every: string | undefined;
  occurrences: string | undefined;
  repeat: string | undefined;
}

// useGetCommimtnetPaymentSchedulePreview shouldn't be called here, we'll need to think about how to refactor this
export const UpcomingSchedulePreview = ({
  amount,
  daysOfMonth,
  daysOfWeek,
  endDate,
  every,
  occurrences,
  repeat,
}: IProps) => {
  const showUpcoming =
    amount &&
    repeat &&
    (occurrences || endDate) &&
    ((repeat !== RepeatEnum.Weekly && repeat !== RepeatEnum.Monthly) || every);

  const { isLoading, upcomingDates } = useGetCommitmentPaymentSchedulePreview({
    daysOfMonth:
      repeat === RepeatEnum.FirstAndFifteenth
        ? [1, 15]
        : (daysOfMonth ?? []).map((day) => parseInt(day, 10)),
    daysOfWeek: daysOfWeek ?? [],
    every: repeat === RepeatEnum.FirstAndFifteenth ? RepeatEnum.Monthly : repeat,
    interval: every ? parseInt(every, 10) : undefined,
    total: occurrences ? parseInt(occurrences, 10) : undefined,
    until: serializeDate(endDate),
  });

  if (!showUpcoming) {
    return null;
  }

  return (
    <>
      <Box mb={4} mt={8}>
        <Heading as="h3">Upcoming Schedule</Heading>
      </Box>
      {isLoading ? (
        <UpcomingScheduleSkeleton />
      ) : (
        <UpcomingSchedule
          amount={amount ? parseFloat(amount) : undefined}
          upcomingDates={upcomingDates}
        />
      )}
    </>
  );
};
